#include<cstdio>
#include<cstring>
#define rep(a,b,c) for(int c(a);c<=(b);++c)
#define drep(a,b,c) for(int c(a);c>=(b);--c)
#define grep(b,c) for(int c(head[b]);c;c=nxt[c])
#define Grep(b,c) for(int &c=h2[b];c;c=nxt[c]) 
typedef long long LL;
inline int read()
{
	int res=0;char ch=getchar();while(ch<'0'||ch>'9')ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();return res;
}
template<typename T> inline T min(const T&x,const T&y){return x<y?x:y;}
template<typename T> inline T max(const T&x,const T&y){return y<x?x:y;}
const int W=19260817,N=40,M=2010;const LL INF=0x3f3f3f3f3f3f3f3fll;
int head[N],des[M],nxt[M],cgt=1,h2[N],s,t,n,m;LL cap[M];
inline void ins(const LL &c,const int &y,const int &x)
{
	nxt[++cgt]=head[x];des[head[x]=cgt]=y;cap[cgt]=c;
	nxt[++cgt]=head[y];des[head[y]=cgt]=x;cap[cgt]=0;
}
int que[N],H,T;LL dep[N];inline bool bfs()
{
	memset(dep,0,sizeof(dep));dep[que[H=T=0]=s]=1;
	while(H<=T){int u=que[H++];grep(u,i){int v=des[i];if(cap[i]&&!dep[v])dep[que[++T]=v]=dep[u]+1;}}return dep[t];
}
inline LL dfs(const int &u=s,LL in=INF)
{
	if(u==t)return in;LL out=0;Grep(u,i)
	{
		int v=des[i];if(!cap[i]||dep[v]!=dep[u]+1)continue;
		LL tmp=dfs(v,min(in,cap[i]));cap[i]-=tmp;in-=tmp;out+=tmp;cap[i^1]+=tmp;if(!in)break;
	}
	return !out?dep[u]=0:out;
}
int main()
{
	n=read();m=read();rep(1,m,i)ins(1ll*W*read()+1,read(),read());
	s=1;t=n;LL res=0;while(bfs())memcpy(h2,head,(n+2)<<2),res+=dfs();printf("%lld %lld\n",res/W,res%W);
}
